import numpy as np

def leaky_relu(z: float, alpha: float = 0.01) -> float | int:
    return float(np.where(z >= 0, z, alpha * z))

tensorflow.code:
import tensorflow as tf

def leaky_relu(z: float, alpha: float = 0.01) -> float | int:
    z_tensor = tf.constant(z, dtype=tf.float32)
    result = tf.nn.leaky_relu(z_tensor, alpha=alpha)
    return float(result.numpy())

pytorch.code:
import torch
import torch.nn.functional as F

def leaky_relu(z: float, alpha: float = 0.01) -> float | int:
    z_tensor = torch.tensor(z, dtype=torch.float32)
    result = F.leaky_relu(z_tensor, negative_slope=alpha)
    return float(result.item())
